/** @type {import('tailwindcss').Config} */
module.exports = {
  content: [
    "./templates/**/*.html",
    "./chat/templates/**/*.html",
  ],
  theme: {
    extend: {},
  },
  plugins: [],
}

/**
 * Chat WebSocket client for streaming responses.
 */

(function() {
    'use strict';

    const messagesContainer = document.getElementById('messages-container');
    const chatForm = document.getElementById('chat-form');
    const messageInput = document.getElementById('message-input');
    const sendBtn = document.getElementById('send-btn');

    let ws = null;
    let currentAssistantMessage = null;

    /**
     * Initialize WebSocket connection.
     */
    function initWebSocket() {
        const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
        const wsUrl = `${protocol}//${window.location.host}/ws/chat/`;

        ws = new WebSocket(wsUrl);

        ws.onopen = function() {
            console.log('WebSocket connected');
        };

        ws.onmessage = function(event) {
            const data = JSON.parse(event.data);

            if (data.type === 'token') {
                appendTokenToMessage(data.content);
            } else if (data.type === 'done') {
                currentAssistantMessage = null;
            } else if (data.type === 'error') {
                appendErrorMessage(data.message);
                currentAssistantMessage = null;
            }
        };

        ws.onclose = function() {
            console.log('WebSocket disconnected');
            // Reconnect after delay
            setTimeout(initWebSocket, 3000);
        };

        ws.onerror = function(error) {
            console.error('WebSocket error:', error);
        };
    }

    /**
     * Append user message to chat.
     */
    function appendUserMessage(text) {
        const template = document.getElementById('user-message-template');
        const clone = template.content.cloneNode(true);
        clone.querySelector('p').textContent = text;
        messagesContainer.appendChild(clone);
        messagesContainer.scrollTop = messagesContainer.scrollHeight;
    }

    /**
     * Create or append to assistant message.
     */
    function appendTokenToMessage(token) {
        if (!currentAssistantMessage) {
            const template = document.getElementById('assistant-message-template');
            const clone = template.content.cloneNode(true);
            messagesContainer.appendChild(clone);
            currentAssistantMessage = clone.querySelector('p');
        }
        currentAssistantMessage.textContent += token;
        messagesContainer.scrollTop = messagesContainer.scrollHeight;
    }

    /**
     * Append error message.
     */
    function appendErrorMessage(message) {
        const div = document.createElement('div');
        div.className = 'flex justify-center';
        div.innerHTML = `<div class="bg-red-100 text-red-800 px-4 py-2 rounded-lg">${escapeHtml(message)}</div>`;
        messagesContainer.appendChild(div);
        messagesContainer.scrollTop = messagesContainer.scrollHeight;
    }

    /**
     * Escape HTML to prevent XSS.
     */
    function escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    /**
     * Send message via WebSocket.
     */
    function sendMessage(message) {
        if (ws && ws.readyState === WebSocket.OPEN) {
            ws.send(JSON.stringify({ message: message }));
        } else {
            appendErrorMessage('Not connected to server');
        }
    }

    /**
     * Handle form submission.
     */
    chatForm.addEventListener('submit', function(event) {
        event.preventDefault();

        const message = messageInput.value.trim();
        if (!message) return;

        appendUserMessage(message);
        sendMessage(message);
        messageInput.value = '';
        sendBtn.disabled = true;

        const checkInterval = setInterval(function() {
            if (!currentAssistantMessage) {
                sendBtn.disabled = false;
                clearInterval(checkInterval);
            }
        }, 100);
    });

    // Initialize on load
    initWebSocket();
})();

